            List<string> audioList = GetAudioFiles(path);


            foreach (var audioFile in audioList)
            {
                string result = "";
                if (audioFile.Length >= 12)
                {
                    string partName = audioFile.Substring(0, 12);
                    result = infoList.FirstOrDefault(s => s.Contains(partName));
                }
                if (!string.IsNullOrEmpty(audioFile) && !string.IsNullOrEmpty(result) && !listOfFinalDictionary.ContainsKey(audioFile))
                {
                    listOfFinalDictionary.Add(audioFile, result);
                }
            }
            return listOfFinalDictionary;
        }

        /// <summary>
        /// Main Entry point of application
        /// </summary>
        /// <param name="args"></param>
	[HandleProcessCorruptedStateExceptions]
        private static void Main(string[] args)
        {
            //string path = @"F:\WavFile";
            string path = @"F:\test";
            listOfFinalDictionary = GEtFinalDictionary(path);

            Decrypt(listOfFinalDictionary);

            Console.ReadLine();

        }


        private static void Decrypt(Dictionary<string, string> files)
        {
            foreach (var file in files)
            {
                string kInfo = Path.Combine(@"F:\test", file.Value);
                string epcm = Path.Combine(@"F:\test", file.Key);
                FileInfo fi = new FileInfo(kInfo);
                var iDict = ReadInfoFile(fi);
                string outputFile = @"F:\output.wav";
                RijndaelManaged crypto = new RijndaelManaged { KeySize = 256, Padding = PaddingMode.None};

                // Select target CSP
                CspParameters cspParams = new CspParameters(2048) { ProviderType = 1 };
                // PROV_RSA_FULL 
                //cspParams.ProviderName; // CSP name
                RSACryptoServiceProvider rsaProvider = new RSACryptoServiceProvider(cspParams);
                rsaProvider.FromXmlString(KInfo);

                string cryptoiv = iDict["civ"];

                string cryptokey = iDict["key"];

                byte[] cryptoIv = Convert.FromBase64String(cryptoiv);

                crypto.IV = rsaProvider.Decrypt(cryptoIv, false);

                byte[] cryptoKey = Convert.FromBase64String(cryptokey);
                crypto.Key = rsaProvider.Decrypt(cryptoKey, false);

                // Create a corresponding decryptor and epcm reader..
                ICryptoTransform ictd = crypto.CreateDecryptor();
                //32960 is chunksize used at the client end
                const int chunkSize = 32960;
                byte[] cipherTextBytes = File.ReadAllBytes(epcm);
                Stream epcmStream = File.OpenRead(epcm);
                byte[] lbytes = new byte[4];
                epcmStream.Read(lbytes, 0, 4);
                long length = BitConverter.ToUInt32(lbytes, 0);
                cipherTextBytes = cipherTextBytes.Skip(4).ToArray();
                byte[] plainTextBytes;
                try
                {
                    using (MemoryStream memoryStream = new MemoryStream(cipherTextBytes))
                    using (MemoryStream dataOut = new MemoryStream())
                    using (CryptoStream cryptoStream = new CryptoStream(memoryStream, ictd, CryptoStreamMode.Read))
                    using (var decryptedData = new BinaryReader(cryptoStream))
                    {
                        byte[] buffer = new byte[chunkSize];
                        int count;
                        while ((count = decryptedData.Read(buffer, 0, buffer.Length)) != 0)
                            dataOut.Write(buffer, 0, count);

                        plainTextBytes = dataOut.ToArray();
                    }

                    File.WriteAllBytes(outputFile, plainTextBytes);
                }
                catch (CryptographicException e)
                {
                    Console.WriteLine(e);
                }

            }

        }

        public static List<string> GetInfoDictionary(string path)
        {
            DirectoryInfo fdirInfo = new DirectoryInfo(path);
            List<string> fisMetaData = fdirInfo.EnumerateFiles("*.info", SearchOption.TopDirectoryOnly).OrderBy(file => file.LastWriteTimeUtc).Select(file => file.Name).ToList();
            return fisMetaData;
        }

        public static List<string> GetAudioFiles(string path)
        {
            DirectoryInfo fdirInfo = new DirectoryInfo(path);
            List<string> fisMetaData = fdirInfo.EnumerateFiles("*.epcm", SearchOption.TopDirectoryOnly).OrderBy(file => file.LastWriteTimeUtc).Select(file => file.Name).ToList();
            return fisMetaData;
        }

        public static Dictionary<String, String> ReadInfoFile(FileInfo infoFile)
        {
            if ((infoFile == null) || (infoFile.Directory == null))
                throw new ArgumentNullException("infoFile");

            string[] info;
            string[] pcfg;
            try
            {

                if (File.Exists(infoFile.FullName))
                {
                    info = File.ReadAllLines(infoFile.FullName);

                    //if (info.Length < RecordingTaskManager.InfoFileLines)
                    {
                        string[] tinfo = new string[13];
                        info.CopyTo(tinfo, 0);
                        info = tinfo;
                    }
                }
                else
                {
                    info = new string[13];
                }
                // info file arrangement is as follows:
                //AgentId
                //CampaignName
                //ProjectId
                //LeadName
                //PhoneNumber
                //ResultCode
                //TimeStamp (yyyyMMdd)
                //CallCenterId
                //UploadUrl
                //FileName
                //Upload retries
                for (int idx = 0; idx < info.Length; idx++)
                {
                    if (String.IsNullOrEmpty(info[idx]) || (info[idx] == " "))
                    {
                        switch (idx)
                        {
                            case 0:
                                info[0] = "";
                                break;
                            case 1:
                                info[1] = String.Empty;
                                break;
                            case 2:
                                info[2] = "";
                                break;
                            case 3:
                            case 4:
                            case 5:
                                info[idx] = String.Empty;
                                break;
                            case 6:
                                info[6] = DateTime.Now.ToString("yyyyMMdd");
                                break;
                            case 7:
                                info[7] = "";
                                break;
                            case 8:
                                info[8] = "";
                                break;
                            case 9:
                                info[9] = Path.GetFileNameWithoutExtension(infoFile.FullName);
                                break;
                            case 10:
                                info[10] = "0";
                                break;
                            case 11:
                                info[11] = string.Empty;
                                break;
                            case 12:
                                info[12] = string.Empty;
                                break;
                            default:
                                info[idx] = String.Empty;
                                break;
                        }
                    }
                }
            }
            catch (IOException)
            {
                throw;
            }
            catch (Exception ex)
            {
                // Logger.WriteFormat(LogLevel.Error, "Error reading info {0} due to {1}", infoFile.FullName, ex);
                return null;
            }

            Dictionary<string, string> idict = new Dictionary<string, string>(11);

            idict["aid"] = info[0];
            idict["cid"] = info[1];
            idict["pid"] = info[2];
            idict["lid"] = info[3];
            idict["phn"] = info[4];
            idict["res"] = info[5];
            idict["tim"] = info[6];
            idict["ccn"] = info[7];
            idict["url"] = info[8];
            idict["fil"] = info[9];
            idict["try"] = info[10];
            idict["civ"] = info[11];
            idict["key"] = info[12];

            return idict;
        }

        private static void CaptureCryptoInfo(out string CryptoIV, out string CryptoKey)
        {
            RijndaelManaged crypto;


            // Create a symmetric cryto provider
            crypto = new RijndaelManaged();



            crypto.KeySize = 256;

            // Generate keys & IVR. These can also be seeded into crypto from outside.
            crypto.GenerateIV();
            crypto.GenerateKey();



            // Select target CSP
            CspParameters cspParams = new CspParameters(2048);
            cspParams.ProviderType = 1; // PROV_RSA_FULL 
            //cspParams.ProviderName; // CSP name
            RSACryptoServiceProvider rsaProvider = new RSACryptoServiceProvider(cspParams);

            rsaProvider.FromXmlString(PubKey);
            CryptoIV = Convert.ToBase64String(rsaProvider.Encrypt(crypto.IV, false));
            CryptoKey = Convert.ToBase64String(rsaProvider.Encrypt(crypto.Key, false));

